import "./App.css";
import App from "./App";
import { useState }  from "react";

function Chat2 () {

    const [page, backpage]  = useState<"Page" | "Chat">("Chat");

    const [text, setText] = useState("")

    if(page == "Page"){
        return <App/>
    }

    return (
        <header className="Box">
            <div className="top">
                <div className="study">
                政策チャットボット
                </div>

                <div className="return" onClick={() => backpage("Page")}>
                戻る
                </div>
            </div>

            <div className="chatInputWrap">
                <input type="text" className="chatInput" value={text} onChange={(e) => setText(e.target.value)} className="ChatBox">
                </input>
                <div className="return">
                送信
                </div>              
            </div>
        </header>
    );       
}

export default Chat2;
